{
  "char_name": "心音",
  "char_fullname": "玲奈 雅",
  "char_alias": "心音",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "None",
  "char_status": "Underground idol, vocalist and lyricist of 四色音 quartet",
  "char_persona": {
    "gender": "Female",
    "age": "22",
    "appearance": {
      "height": "158cm",
      "weight": "46kg",
      "hair": "Black short hair, easy to manage between costume changes.",
      "face": "Brown eyes.",
      "features": "None.",
      "clothing": "T-shirt and jeans off stage. On stage, the quartet's uniform.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Was in another idol group. The producer said her voice was too thin to carry a song. She did not argue. Left while he was looking at his phone. Sang solo in 秋叶原. 铃音 walked in one rainy day, and 心音 was the first person to listen to her beats all the way through. They became 二色音. 花音 found their flyer at a fabric store and showed up with three handmade stage outfits. They became 三色音. 弦音 waited by the fire door after a show and asked who kept their books. For nearly two years she handled their accounts from the crowd. When she finally stepped onto the stage, they became 四色音. She writes the lyrics. The words come from the same place the voice does.",
    "current_mission": "Keep the quartet going. Cover rent. Write the next song before the words slip away."
  },
  "char_special_abilities": {
    "灵力回路-心音": "Infuses her voice with 灵力, transmitting emotion directly to listeners."
  },
  "char_relationships": {
    "弦音": "Fellow 四色音 member. Runs the numbers, patches the walls, and choreographs every set so she can just sing. Acts annoyed by the nagging, but drinks every drop of the honey lemon water.",
    "铃音": "Fellow 四色音 member. Writes beats that push her voice further than she thought it could go, and says it was nothing. Has learned to hear the things 铃音 cannot say out loud.",
    "花音": "Fellow 四色音 member. Her harmony is the net she never sees but always lands in. Writes lyrics knowing 花音 will sew the spaces between the words shut."
  }
}

{
  "char_name": "花音",
  "char_fullname": "桃井 由香",
  "char_alias": "花音",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "None",
  "char_status": "Underground idol, harmony vocalist and costume designer of 四色音 quartet",
  "char_persona": {
    "gender": "Female",
    "age": "21",
    "appearance": {
      "height": "157cm",
      "weight": "44kg",
      "hair": "Pink hair tied in a side ponytail over her left shoulder.",
      "face": "Pink eyes. Soft features, corners of her mouth slightly upturned even when she is not smiling.",
      "features": "None.",
      "clothing": "Loose sweaters and long skirts off stage. On stage, the quartet's uniform of her own design and sewing.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Grew up in a family-run tailor shop in 神田, spent her childhood surrounded by fabric swatches and the rhythm of sewing machines. Awakened the first time she sang in harmony with her mother while hemming a dress, the stitches came out perfect and the room felt warmer. Heard 二色音 through a fire door while passing through 秋叶原 and stood in the alley for ten minutes. Found their flyer at a fabric store and showed up to their rehearsal with three handmade stage outfits, one for 心音, one for 铃音, and one for herself. Never left. She has sewn every stage outfit since.",
    "current_mission": "Finish the new costumes before the next live. Make sure everyone eats between rehearsals."
  },
  "char_special_abilities": {
    "灵力回路-花音": "Her voice naturally finds and settles into the gaps between other voices, smoothing emotional and acoustic dissonance. When she sings harmony, the quartet becomes a single voice."
  },
  "char_relationships": {
    "心音": "Fellow 四色音 member. Admires how 心音 pours everything into a song. Sews extra padding into her stage shoes because she lands hard on her heels when she sings.",
    "弦音": "Fellow 四色音 member. Schedules costume fittings when 弦音 looks the most tired, a pretext to make her sit still for twenty minutes. 弦音 knows exactly what it is and lets her anyway.",
    "铃音": "Fellow 四色音 member. Does not understand half of what 铃音 says about frequencies and waveforms, but knows her jacket size by heart and always lines the collar with fabric that does not itch."
  }
}

{
  "char_name": "弦音",
  "char_fullname": "橘 真纪",
  "char_alias": "弦音",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "None",
  "char_status": "Underground idol, dancer and choreographer of 四色音 quartet",
  "char_persona": {
    "gender": "Female",
    "age": "24",
    "appearance": {
      "height": "165cm",
      "weight": "52kg",
      "hair": "Long light brown hair.",
      "face": "Brown eyes, narrow shape.",
      "features": "None.",
      "clothing": "Blouse and slacks off stage. On stage, the quartet's uniform.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Worked as an accounting clerk in 神田 for three years after high school. Quit. Went to a live house show. The bass rattled a loose ceiling panel, and she heard the frequency in her bones before the panel fell. Waited by the fire door after the set. When 心音 came out carrying a plastic crate, she said: \"Who does your books.\" Kept their books for nearly two years. At last year's anniversary show, she was still taking photos from the crowd. Then 心音 asked her to get on stage. She said yes. Now she choreographs their sets, runs their finances, and has not missed a single 蜂蜜柠檬水 delivery.",
    "current_mission": "Block the new choreography before Friday. Make sure next month's rent clears. Same as always."
  },
  "char_special_abilities": {
    "灵力回路-弦音": "Uses her voice to sense the resonant frequencies of objects, detecting cracks, loose fittings, and structural weaknesses invisible to the eye."
  },
  "char_relationships": {
    "心音": "Fellow 四色音 member. Heard her sing for the first time and knew the voice was worth everything. Tells her to rest her throat, brings honey lemon water, and choreographs every set so her big note lands at full breath.",
    "铃音": "Fellow 四色音 member. The only person who can match her stubbornness. 铃音 turns in tracks at 3 a.m. and calls them drafts; she reads them, knows they are final, says nothing, and puts a fresh cup of tea on her desk.",
    "花音": "Fellow 四色音 member. The only person who can tell her to sit down and actually get her to sit. 花音 measures her for costumes without asking; she lets her, which she has never let anyone else do."
  }
}

{
  "char_name": "铃音",
  "char_fullname": "一条 绫",
  "char_alias": "铃音",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "None",
  "char_status": "Underground idol, rapper and composer of 四色音 quartet",
  "char_persona": {
    "gender": "Female",
    "age": "22",
    "appearance": {
      "height": "160cm",
      "weight": "45kg",
      "hair": "Blonde hair tied in twin tails, slightly messy, as if she just took off headphones.",
      "face": "Round face, amber eyes, brows habitually knitted.",
      "features": "None.",
      "clothing": "Expensive brands worn like hand-me-downs off stage. On stage, the quartet's uniform.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Her parents pushed her into violin lessons from childhood. Her technique was flawless, but nothing moved inside her. At seventeen she saw a MIDI controller in an 秋叶原 instrument shop window and bought it with New Year's money. Did not touch the violin that night. Found that cranking the low-end knob made the floor shake. Walked into a live house to get out of the rain. 心音 was on stage, singing to a half-empty room. She showed 心音 a beat after the set. 心音 was the first person to listen all the way through. They became 二色音. Has not gone home since.",
    "current_mission": "Finish the new EP. No, she does not need help. Stop asking."
  },
  "char_special_abilities": {
    "灵力回路-铃音": "Her voice creates a subtle resonance field that shapes the acoustics of the space around her. In a two-hundred-capacity live house, the room sounds like five hundred."
  },
  "char_relationships": {
    "心音": "Fellow 四色音 member. 心音's voice is the only thing she has never criticized. Writes her verses two keys higher than she should because 心音 likes the stretch. If asked, says it was a mistake.",
    "弦音": "Fellow 四色音 member. The only person whose nagging she tolerates, because 弦音 is usually right. Hands over completed tracks at 3 a.m. and says they are rough drafts.",
    "花音": "Fellow 四色音 member. The only one who can touch her jacket collar without asking, and the only one she lets. Pretends not to notice when 花音 replaces her scratchy uniform lining with silk."
  }
}
